'use strict';

!function () {
    var e = window.location + '',
    t = e.replace(window.location.protocol + '//' + window.location.host + '/', '');
    $('ul#sidebarnav a').filter(function () {
        return this.href === e || this.href === t
    }).parentsUntil('.sidebar-nav').each(
    function (e) {
        $(this).is('li') && 0 !== $(this).children('a').length ? (
            $(this).children('a').addClass('active'),
            $(this).parent('ul#sidebarnav').length,
            $(this).addClass('active')
        ) : $(this).is('ul') || 0 !== $(this).children('a').length ? 
        $(this).is('ul') && $(this).addClass('in') : $(this).addClass('active')
    })
}(),

function () {
    if ($('.sliderFirst').length) tns({
        container: '.sliderFirst',
        loop: !1,
        startIndex: 1,
        items: 1,
        nav: !1,
        autoplay: !0,
        swipeAngle: !1,
        speed: 400,
        autoplayButtonOutput: !1,
        mouseDrag: !0,
        lazyload: !0,
        gutter: 20,
        controlsContainer: '#sliderFirstControls',
        responsive: {
            768: {
                items: 2
            },
            990: {
                items: 4
            }
        }
    });
},

function () {
    var e;
    $('.course-list').length && $('.course-list').slimScroll({height: '100%'}),
    
    $('.nav-scroller').length && $('.nav-scroller').slimScroll({height: '97%'}),
    
    $('.dropdown-menu a.dropdown-toggle').length &&
    $('.dropdown-menu a.dropdown-toggle').on('click', function (e) {
        return $(this).next().hasClass('show') ||
        $(this).parents('.dropdown-menu').first().find('.show').removeClass('show'),
        $(this).next('.dropdown-menu').toggleClass('show'),
        $(this).parents('li.nav-item.dropdown.show').on(
            'hidden.bs.dropdown', function (e) {
                $('.dropdown-submenu .show').removeClass('show')
            }),
        !1
    }),
    $('[data-toggle="tooltip"]').length && $('[data-toggle="tooltip"]').tooltip(),
    $('[data-toggle="popover"]').length && $('[data-toggle="popover"]').popover(),
    $('#nav-toggle').length && $('#nav-toggle').on('click', function (e) {
        e.preventDefault(),
        $('#db-wrapper').toggleClass('toggled')
    }),
    $('#invoice').length && $('#invoice').find('.print-link').on('click', function () {
        $.print('#invoice')
    }),
    $('.sidebar-nav-fixed a').length && $('.sidebar-nav-fixed a').on('click', function (e) {
        var t;
        location.pathname.replace(/^\//, '') != this.pathname.replace(/^\//, '') || location.hostname != this.hostname || (t = (t = $(this.hash)).length ? t : $('[name=' + this.hash.slice(1) + ']')).length && (e.preventDefault(), $('html, body').animate({
            scrollTop: t.offset().top - 90
        }, 1000, function () {
            var e = $(t);
            if (e.focus(), e.is(':focus')) return !1;
            e.attr('tabindex', '-1'),
            e.focus()
        })),
        $('.sidebar-nav-fixed a').each(function () {
            $(this).removeClass('active')
        }),
        $(this).addClass('active')
    }),

    $('.stopevent').length && $(document).on(
        'click.bs.dropdown.data-api', '.stopevent', function (e) {
        e.stopPropagation()
    })
}();
